local LP = game:GetService("Players").LocalPlayer local flying = false local speed = 50 local bv, bg local sg = Instance.new("ScreenGui", LP.PlayerGui) sg.Name = "IlayFly" local main = Instance.new("Frame", sg) main.Size = UDim2.new(0, 150, 0, 100) main.Position = UDim2.new(0.5, -75, 0.5, -50) main.BackgroundColor3 = Color3.fromRGB(40, 40, 40) main.Draggable = true local btn = Instance.new("TextButton", main) btn.Size = UDim2.new(1, 0, 1, 0) btn.Text = "ilay's fly: OFF" btn.TextColor3 = Color3.new(1,1,1) btn.BackgroundTransparency = 1 btn.MouseButton1Click:Connect(function() flying = not flying if flying then btn.Text = "ilay's fly: ON" local root = LP.Character:WaitForChild("HumanoidRootPart") bg = Instance.new("BodyGyro", root) bg.maxTorque = Vector3.new(9e9, 9e9, 9e9) bv = Instance.new("BodyVelocity", root) bv.maxForce = Vector3.new(9e9, 9e9, 9e9) task.spawn(function() while flying do task.wait() bg.cframe = workspace.CurrentCamera.CFrame bv.velocity = workspace.CurrentCamera.CFrame.LookVector * speed end end) else btn.Text = "ilay's fly: OFF" if bg then bg:Destroy() end if bv then bv:Destroy() end end end)
